import{_ as t,o as a,c as d,ai as o}from"./chunks/framework.DsLHkhEs.js";const h=JSON.parse('{"title":"DNS Setup","description":"","frontmatter":{},"headers":[],"relativePath":"network/DNS Setup.md","filePath":"network/DNS Setup.md"}'),r={name:"network/DNS Setup.md"};function s(n,e,i,p,u,c){return a(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="dns-setup" tabindex="-1">DNS Setup <a class="header-anchor" href="#dns-setup" aria-label="Permalink to “DNS Setup”">​</a></h1><p>Its recommended to create two subdomains for the VoIP system to make things easier. The subdomains are used for the reverse proxies and they should point to the server where you run DCTS and livekit.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Example proxies for caddy and nginx can be found in <a href="./Reverse Proxy Setup">Reverse Proxy Setup</a>. How to setup caddy can be found in <a href="./Caddy Setup">Caddy Setup</a>.</p></div><table tabindex="0"><thead><tr><th>Type</th><th>Name</th><th>Content</th><th>Proxy needed?</th></tr></thead><tbody><tr><td>A</td><td>chat</td><td>your.ip.address</td><td>Yes</td></tr><tr><td>A</td><td>lk</td><td>your.ip.address</td><td>Yes</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Please note that you will need to have valid TLS certificates for your subdomains and access to the cert files as they will be needed later for the configuration of livekit. You can install caddy to handle the TLS certs automatically. More on that can be found in <a href="./Caddy Setup">Caddy Setup</a> and <a href="./Reverse Proxy Setup">Reverse Proxy Setup</a>.</p></div>',5)])])}const S=t(r,[["render",s]]);export{h as __pageData,S as default};
